/* Tymczasowy loader pdf-lib dla Kalkulator/test.html.
 * Docelowo ten plik powinien zostać podmieniony na pełny lokalny build:
 * https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/dist/pdf-lib.min.js
 * Dzięki temu test.html nie wymaga zmiany ścieżki skryptu.
 */
(function loadPdfLibFallback(){
  if (window.PDFLib) return;
  var script = document.createElement('script');
  script.src = 'https://cdn.jsdelivr.net/npm/pdf-lib@1.17.1/dist/pdf-lib.min.js';
  script.async = false;
  script.onload = function(){
    window.dispatchEvent(new CustomEvent('pdf-lib-ready'));
  };
  script.onerror = function(){
    console.error('Nie udało się załadować pdf-lib z CDN. Podmień Kalkulator/vendor/pdf-lib.min.js na pełny lokalny plik pdf-lib.min.js.');
  };
  document.head.appendChild(script);
})();
